bool collides_with_wall(float x, float y, float w, float h)
{

    int startCol = (int)(x / WALL_TILE_SIZE);
    int endCol   = (int)((x + w - 1) / WALL_TILE_SIZE);
    int startRow = (int)(y / WALL_TILE_SIZE);
    int endRow   = (int)((y + h - 1) / WALL_TILE_SIZE);

    // Utanför kartan räknas som vägg — hindrar spelaren från att lämna världen

    if (startCol < 0 || startRow < 0 || endCol >= WALL_MAP_COLS || endRow >= WALL_MAP_ROWS)
    {
        return true;
    }

    for (int row = startRow; row <= endRow; row++)
    {
        for (int col = startCol; col <= endCol; col++)
        {
            if (wall_map[row][col])
            {
                return true;
            }
        }
    }
    return false;

}
